import{_ as t}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as a,a as i,o as s}from"./app-C1uFFeqg.js";const n={};function l(o,e){return s(),a("div",null,[...e[0]||(e[0]=[i('<ul><li>Interfaces and abstract classes provide a more structured way to separate interface from implementation</li><li>Inheritance is specialisation; interface is generalisation</li></ul><h2 id="interfaces" tabindex="-1"><a class="header-anchor" href="#interfaces"><span>Interfaces</span></a></h2><ul><li><code>implements</code></li><li>An interface is a contract of what the classes <strong>can</strong> do</li><li>An abstract class taken to the extreme,thus more flexibility (complete decoupling)</li><li>Refer to different types of objects with one identical interface type <ul><li>Generalisation</li><li>Capability of putting different types of objects into one data structure</li><li>Less effort for code alteration</li></ul></li><li>One class can implement several interfaces <ul><li>&quot;Multiple inheritance&quot;: A class can be upcast to more than one base type with interfaces</li></ul></li><li>Interface cannot be instantiated</li><li>Methods in interfaces are implicitly <code>public</code></li><li>Fields in interfaces are implicitly constant (<code>public static final</code>)</li><li>SInce Java 8 interface can have <code>static</code> methods</li><li>An interface can extend another interface</li><li>Interface can have <code>default</code> methods which can have method body <ul><li>Java 8 feature</li><li>Make refactoring interface easier</li><li>Java 9 allows <code>private</code> methods in interface that can be used in <code>default</code> methods inside interface</li></ul></li><li>Type of Interface <ul><li><p>Normal interface</p></li><li><p><strong>Functional Interface</strong></p><ul><li>Has only one abstract function</li></ul></li><li><p>Marker Interface</p><ul><li>Has no member fields or methods</li><li>Eg. <code>Serializable</code>, <code>Cloneable</code>, <code>RandomAccess</code></li></ul></li></ul></li></ul><h2 id="abstract-classes" tabindex="-1"><a class="header-anchor" href="#abstract-classes"><span>Abstract Classes</span></a></h2><ul><li>An abstract class is a class that is declared <code>abstract</code></li><li>Contain a mix of methods with or without implementation</li><li>An abstract method is a method that is declared <code>abstract</code> without an implementation</li><li>Abstract class cannot be instantiated, but can be subclassed</li><li>When an abstract class is subclassed, the subclass usually provides implementations for all of the abstract methods in its superclass. However, if it doesn&#39;t, then the subclass must also be declared <code>abstract</code></li><li>A subclass of a non-abstract superclass can be <code>abstract</code></li></ul><h2 id="interfaces-vs-abstract-classes" tabindex="-1"><a class="header-anchor" href="#interfaces-vs-abstract-classes"><span>Interfaces vs. Abstract Classes</span></a></h2><ul><li>Abstract Classes <ul><li>Purpose is to <strong>provide a common definition of a base class that multiple derived classes can share</strong></li><li>Share code among several <strong>closely related classes</strong></li><li>Expect classes that extend your abstract class to have many common methods or fields or required access modifier other than <code>public</code></li><li>Want to declare non static or non final fields</li><li>Provide default implementations of certain methods but leave other methods open to being overridden</li></ul></li><li>Interfaces <ul><li>Purpose is <strong>abstraction</strong></li><li>Expect unrelated classes will implement your interface</li><li>Want to specify the behavior of a particular data type, but not concern about who implements its behavior</li><li>Want to separate different behaviors</li></ul></li></ul>',7)])])}const d=t(n,[["render",l]]),p=JSON.parse(`{"path":"/notes/language/java/interface.html","title":"Interfaces and Abstract Classes","lang":"en-US","frontmatter":{"title":"Interfaces and Abstract Classes","category":["Note"],"tag":["Language","Java"],"footer":false,"editLink":false,"description":"Interfaces and abstract classes provide a more structured way to separate interface from implementation Inheritance is specialisation; interface is generalisation Interfaces imp...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Interfaces and Abstract Classes\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-12T13:20:34.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Hadjshell\\",\\"url\\":\\"https://github.com/hadjShell\\"}]}"],["meta",{"property":"og:url","content":"https://hadjshell.netlify.app/notes/language/java/interface.html"}],["meta",{"property":"og:site_name","content":"Hadjshell's Field"}],["meta",{"property":"og:title","content":"Interfaces and Abstract Classes"}],["meta",{"property":"og:description","content":"Interfaces and abstract classes provide a more structured way to separate interface from implementation Inheritance is specialisation; interface is generalisation Interfaces imp..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2026-07-12T13:20:34.000Z"}],["meta",{"property":"article:tag","content":"Java"}],["meta",{"property":"article:tag","content":"Language"}],["meta",{"property":"article:modified_time","content":"2026-07-12T13:20:34.000Z"}]]},"git":{"createdTime":1783862434000,"updatedTime":1783862434000,"contributors":[{"name":"张家源","username":"","email":"davidzhang0880@gmail.com","commits":1}]},"readingTime":{"minutes":1.31,"words":392},"filePathRelative":"notes/language/java/interface.md","excerpt":"","autoDesc":true}`);export{d as comp,p as data};
